// Extract message from incoming webhook
// Supports: WhatsApp Cloud API format OR simple JSON { phone, message }
const body = .first().json.body || .first().json;

let senderPhone = '';
let messageText = '';
let senderName = '';

// Format 1: Simple webhook { phone, message, name? }
if (body.phone && body.message) {
  senderPhone = String(body.phone);
  messageText = String(body.message);
  senderName = body.name || 'Customer';
}
// Format 2: WhatsApp Cloud API format
else if (body.entry) {
  const entry = body.entry[0];
  const changes = entry.changes[0];
  const value = changes.value;
  if (!value.messages || !value.messages[0]) return [];
  const msg = value.messages[0];
  senderPhone = msg.from;
  messageText = msg.text?.body || msg.interactive?.button_reply?.title || '';
  if (value.contacts && value.contacts[0]) {
    senderName = value.contacts[0].profile?.name || '';
  }
}
// Format 3: Fallback { from, text/body }
else if (body.from) {
  senderPhone = body.from;
  messageText = body.text?.body || body.body || '';
  senderName = body.profile_name || '';
}

// Normalize phone
senderPhone = senderPhone.replace(/^+/, '');
if (senderPhone.startsWith('0')) senderPhone = '60' + senderPhone.substring(1);

if (!senderPhone || !messageText) return [];

return {
  json: {
    senderPhone,
    messageText: messageText.trim(),
    senderName: senderName || 'Customer',
    timestamp: new Date().toISOString()
  }
};

const customer = $('Lookup Customer').first().json;
const msg = $('Extract Message').first().json;
const config = $('Config').first().json;

// Handle array response from RPC
const data = Array.isArray(customer) ? customer[0] : customer;

const customerName = data?.customer_name || msg.senderName || 'Customer';
const customerType = data?.customer_type || 'B2C';
const isRegistered = data?.is_registered || false;
const pricingLabel = customerType === 'B2B' ? 'Wholesale/Merchant' : 'Retail';
const priceField = customerType === 'B2B' ? 'merchant_price' : 'retail_price';

return {
  json: {
    senderPhone: msg.senderPhone,
    messageText: msg.messageText,
    senderName: msg.senderName,
    customerName,
    customerType,
    isRegistered,
    pricingLabel,
    priceField,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_KEY: config.SUPABASE_KEY,
    WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
    WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
    WEBSITE_URL: config.WEBSITE_URL,
    ADMIN_PHONE: config.ADMIN_PHONE
  }
};

