const body = $input.first().json.body || $input.first().json;
const config = $('Notification Config').first().json;

// Supabase database webhook sends: type, table, record, old_record
const table = body.table || '';
const eventType = body.type || ''; // INSERT, UPDATE, DELETE
const record = body.record || {};
const oldRecord = body.old_record || {};

let notifType = 'UNKNOWN';
let data = { ...record };

if (table === 'orders') {
  if (eventType === 'INSERT') {
    notifType = 'ORDER_CREATED';
  } else if (eventType === 'UPDATE') {
    // Check what changed
    if (record.status !== oldRecord.status) {
      notifType = 'ORDER_STATUS_CHANGED';
    }
    if (record.tracking_number && !oldRecord.tracking_number) {
      notifType = 'TRACKING_NUMBER_ADDED';
    }
    if (record.payment_state !== oldRecord.payment_state) {
      notifType = 'PAYMENT_STATE_CHANGED';
    }
  }
} else if (table === 'returns') {
  if (eventType === 'INSERT') {
    notifType = 'RETURN_CREATED';
  } else if (eventType === 'UPDATE' && record.status !== oldRecord.status) {
    notifType = 'RETURN_STATUS_CHANGED';
  }
}

// Normalize phone
let customerPhone = record.customer_phone || record.phone || '';
customerPhone = customerPhone.replace(/^\+/, '');
if (customerPhone.startsWith('0')) {
  customerPhone = '60' + customerPhone.substring(1);
}

return {
  json: {
    notifType,
    table,
    record: data,
    oldRecord,
    customerPhone,
    customerName: record.customer_name || record.name || 'Customer',
    orderNo: record.order_no || record.order_number || '',
    total: record.total || record.grand_total || 0,
    status: record.status || '',
    oldStatus: oldRecord.status || '',
    paymentState: record.payment_state || '',
    oldPaymentState: oldRecord.payment_state || '',
    deliveryMethod: record.delivery_method || record.shipping_method || '',
    courierProvider: record.courier_provider || record.courier || '',
    trackingNumber: record.tracking_number || '',
    reason: record.reason || record.return_reason || '',
    timestamp: new Date().toISOString(),
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_KEY: config.SUPABASE_KEY,
    WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
    WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
    WEBSITE_URL: config.WEBSITE_URL,
    ADMIN_PHONE: config.ADMIN_PHONE
  }
};

