const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;
const status = d.status;
let customerMsg = '';
let adminMsg = '';

switch (status) {
  case 'packing':
    const packingDelivery = d.deliveryMethod === 'self-pickup' ? 'collection' : 'delivery';
    customerMsg = `📦 *Order Being Packed*\n\nYour order #${d.orderNo} is now being packed by our warehouse team.\n\nWe'll update you once it's ready for ${packingDelivery}.`;
    adminMsg = `📦 Order #${d.orderNo} status changed to PACKING`;
    break;

  case 'ready_for_collection':
    customerMsg = `📍 *Ready for Collection!*\n\nYour order #${d.orderNo} is ready for pickup!\n\n📍 *Location:* Auto Lab Sdn Bhd\nNo 17, Jalan 7/98B, Cheras Utama\n56100 Kuala Lumpur\n\n🕐 *Operating Hours:*\nMon-Fri: 9:00 AM - 6:00 PM\nSat: 9:00 AM - 1:00 PM\n\nPlease bring your order confirmation. Thank you! 🙏`;
    adminMsg = `📍 Order #${d.orderNo} is READY FOR COLLECTION`;
    break;

  case 'out_for_delivery':
    const trackingLink = d.trackingNumber ? `https://www.jtexpress.my/tracking?billcode=${d.trackingNumber}` : '';
    customerMsg = `🚚 *Out for Delivery!*\n\nYour order #${d.orderNo} is on its way!\n\n📦 *Courier:* ${d.courierProvider}\n🔍 *Tracking:* ${d.trackingNumber}\n${trackingLink ? '🔗 ' + trackingLink : ''}\n\nEstimated delivery: 2-4 business days.`;
    adminMsg = `🚚 Order #${d.orderNo} is OUT FOR DELIVERY (${d.courierProvider} - ${d.trackingNumber})`;
    break;

  case 'completed':
    customerMsg = `✅ *Order Delivered!*\n\nYour order #${d.orderNo} has been delivered. Thank you for choosing AutoLab! 🙏\n\nIf you have any issues, contact us:\n📱 wa.me/60342977668\n📞 03-4297 7668\n\nLeave us a review at ${websiteUrl}/my-orders 💚`;
    adminMsg = `✅ Order #${d.orderNo} COMPLETED`;
    break;

  case 'cancelled':
    customerMsg = `❌ *Order Cancelled*\n\nYour order #${d.orderNo} has been cancelled.\n\nIf this was a mistake, please contact us:\n📱 wa.me/60342977668`;
    adminMsg = `❌ Order #${d.orderNo} CANCELLED`;
    break;

  default:
    customerMsg = `📦 Your order #${d.orderNo} status has been updated to: *${status}*`;
    adminMsg = `📦 Order #${d.orderNo} status: ${status}`;
}

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const trackingLink = d.trackingNumber ? `https://www.jtexpress.my/tracking?billcode=${d.trackingNumber}` : '';

const customerMsg = `📬 *Tracking Number Available*\n\nYour order #${d.orderNo} tracking is ready:\n\n📦 *Courier:* ${d.courierProvider}\n🔍 *Tracking:* ${d.trackingNumber}\n🔗 Track here: ${trackingLink}`;

const adminMsg = `📬 Tracking added to Order #${d.orderNo}: ${d.courierProvider} - ${d.trackingNumber}`;

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;
const state = d.paymentState;
let customerMsg = '';
let adminMsg = '';

switch (state) {
  case 'submitted':
    customerMsg = `📸 *Payment Proof Received*\n\nWe've received your payment proof for order #${d.orderNo}.\nOur team will verify it within 1-2 hours during business hours.`;
    adminMsg = `💳 *PAYMENT PROOF SUBMITTED*\n\n📋 #${d.orderNo}\n👤 ${d.customerName}\n💰 RM${Number(d.total).toFixed(2)}\n\n⚡ Review at: ${websiteUrl}/admin/orders`;
    break;

  case 'approved':
    customerMsg = `✅ *Payment Verified!*\n\nYour payment for order #${d.orderNo} (RM${Number(d.total).toFixed(2)}) has been approved!\nWe'll start processing your order now.`;
    adminMsg = `✅ Payment APPROVED for Order #${d.orderNo} (RM${Number(d.total).toFixed(2)})`;
    break;

  case 'rejected':
    customerMsg = `❌ *Payment Rejected*\n\nSorry, your payment for order #${d.orderNo} could not be verified.\nPlease resubmit or contact us:\n📱 wa.me/60342977668`;
    adminMsg = `❌ Payment REJECTED for Order #${d.orderNo}`;
    break;

  default:
    customerMsg = `💳 Your payment status for order #${d.orderNo} has been updated to: *${state}*`;
    adminMsg = `💳 Payment state for Order #${d.orderNo}: ${state}`;
}

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;
const websiteUrl = d.WEBSITE_URL;

const customerMsg = `🔁 *Return Request Received*\n\nWe've received your return request for order #${d.orderNo}.\n📝 *Reason:* ${d.reason}\n\nOur team will review it and get back to you shortly.`;

const adminMsg = `🔁 *NEW RETURN REQUEST*\n\n📋 Return for Order #${d.orderNo}\n👤 ${d.customerName}\n📝 Reason: ${d.reason}\n\nReview at: ${websiteUrl}/admin/returns`;

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const d = $input.first().json;

const customerMsg = `🔁 *Return Update*\n\nYour return request for order #${d.orderNo} has been updated to: *${d.status}*\n\nIf you have questions, contact us:\n📱 wa.me/60342977668`;

const adminMsg = `🔁 Return for Order #${d.orderNo} status: ${d.status}`;

return {
  json: {
    ...d,
    customerMsg,
    adminMsg
  }
};

const items = $input.all();
const config = $('Cron Config').first().json;
const now = new Date();
const results = [];

for (const item of items) {
  const order = item.json;

  // Skip if no phone
  let phone = order.customer_phone || order.phone || '';
  phone = phone.replace(/^\+/, '');
  if (phone.startsWith('0')) {
    phone = '60' + phone.substring(1);
  }
  if (!phone) continue;

  const createdAt = new Date(order.created_at);
  const hoursAgo = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60);

  let reminderTier = '';
  let reminderMsg = '';
  const customerName = order.customer_name || 'Customer';
  const orderNo = order.order_no || order.order_number || '';
  const total = Number(order.total || order.grand_total || 0).toFixed(2);

  if (hoursAgo < 24) {
    reminderTier = 'gentle';
    reminderMsg = `👋 *Friendly Reminder*\n\nHi ${customerName}, your order #${orderNo} (RM${total}) is awaiting payment.\n\nComplete your payment to start processing! 🙏`;
  } else if (hoursAgo < 48) {
    reminderTier = 'nudge';
    reminderMsg = `⏰ *Payment Reminder*\n\nHi ${customerName}, your order #${orderNo} (RM${total}) is still unpaid.\n\nPlease complete payment soon to avoid cancellation.\n📱 Need help? wa.me/60342977668`;
  } else if (hoursAgo < 72) {
    reminderTier = 'urgent';
    reminderMsg = `⚠️ *Action Required*\n\nHi ${customerName}, your order #${orderNo} (RM${total}) will be *auto-cancelled in 24 hours* if payment is not received.\n\nPlease pay now or contact us for assistance.\n📱 wa.me/60342977668`;
  } else {
    // > 72h: skip, will be auto-cancelled
    continue;
  }

  results.push({
    json: {
      customerPhone: phone,
      customerName,
      orderNo,
      total,
      reminderTier,
      reminderMsg,
      hoursAgo: Math.round(hoursAgo),
      WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
      WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
      WEBSITE_URL: config.WEBSITE_URL,
      ADMIN_PHONE: config.ADMIN_PHONE,
      SUPABASE_URL: config.SUPABASE_URL,
      SUPABASE_KEY: config.SUPABASE_KEY
    }
  });
}

return results;

const items = $input.all();
const config = $('Cron Config').first().json;
const results = [];

for (const item of items) {
  const order = item.json;

  // Skip if response is not an array of cancelled orders
  if (!order.order_no && !order.order_number) continue;

  let phone = order.customer_phone || order.phone || '';
  phone = phone.replace(/^\+/, '');
  if (phone.startsWith('0')) {
    phone = '60' + phone.substring(1);
  }
  if (!phone) continue;

  const customerName = order.customer_name || 'Customer';
  const orderNo = order.order_no || order.order_number || '';

  const cancelMsg = `🚫 *Order Auto-Cancelled*\n\nHi ${customerName}, your order #${orderNo} has been cancelled due to non-payment after 72 hours.\n\nYou're welcome to place a new order anytime at ${config.WEBSITE_URL} 🙏`;

  results.push({
    json: {
      customerPhone: phone,
      customerName,
      orderNo,
      cancelMsg,
      WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
      WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL,
      ADMIN_PHONE: config.ADMIN_PHONE
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];
